func TestAttack_ConcurrentReadWriteSameEntity(t *testing.T) {
	comp := createTestComponentWithMockKV(t)
	ctx := context.Background()
	entityID := "contested-entity"

	const numWriters = 50
	const numReaders = 50

	var wg sync.WaitGroup

	// Concurrent writers
	for i := 0; i < numWriters; i++ {
		wg.Add(1)
		go func(id int) {
			defer wg.Done()
			for j := 0; j < 10; j++ {
				_ = comp.UpdateOutgoingIndex(ctx, entityID, "target", "predicate")
				_ = comp.UpdateIncomingIndex(ctx, entityID, "source", "predicate")
			}
		}(i)
	}

	// Concurrent readers (health checks)
	for i := 0; i < numReaders; i++ {
		wg.Add(1)
		go func() {
			defer wg.Done()
			for j := 0; j < 10; j++ {
				_ = comp.Health()
				_ = comp.DataFlow()
			}
		}()
	}

	wg.Wait()

	// If we get here without race detector failures, test passes
}

